    def is_even(n):
        return n % 2 == 0

print(MathUtils.is_even(4))
print(MathUtils.is_even(7))

import math
from dataclasses import dataclass, field

@dataclass
class Circle:
    radius: float = field(default=1.0)

    def __post_init__(self):
        if self.radius <= 0:
            raise ValueError("Radius must be positive")

    @property
    def area(self):
        return math.pi * self.radius ** 2

c = Circle(3.0)
print(round(c.area, 2))

class Vector2D:
    __slots__ = ("x", "y")

    def __init__(self, x, y):
        self.x = x
        self.y = y

    def magnitude(self):
        return (self.x ** 2 + self.y ** 2) ** 0.5

v = Vector2D(3, 4)
print(v.magnitude())

def repeat(n):
    def decorator(func):
        def wrapper(*args, **kwargs):
            for _ in range(n):
                func(*args, **kwargs)
        return wrapper
    return decorator

@repeat(3)
def say(msg):
    print(msg)

say("Hi")

class CallCounter:
    def __init__(self, func):
        self.func = func
        self.count = 0

    def __call__(self, *args, **kwargs):
        self.count += 1
        return self.func(*args, **kwargs)

@CallCounter
def greet(name):
    print(f"Hello, {name}")

greet("Alice")
greet("Bob")
print(greet.count)

def chain(*iterables):
    for iterable in iterables:
        yield from iterable

for value in chain([1, 2], [3, 4], [5]):
    print(value)

from abc import ABC, abstractmethod
import math

class Shape(ABC):
    @abstractmethod
    def area(self) -> float:
        pass

class Rectangle(Shape):
    def __init__(self, width, height):
        self.width = width
        self.height = height

    def area(self):
        return self.width * self.height

class Circle(Shape):
    def __init__(self, radius):
        self.radius = radius

    def area(self):
        return math.pi * self.radius ** 2

print(round(Rectangle(4, 5).area(), 2))
print(round(Circle(3).area(), 2))

class Flyable:
    def move(self):
        return "Flying"

class Swimmable:
    def move(self):
        return "Swimming"

class Duck(Flyable, Swimmable):
    def describe(self):
        return "I am a duck that can: " + super().move()

d = Duck()
print(d.move())
print(d.describe())

def merge_dicts(d1: dict[str, int], d2: dict[str, int]) -> dict[str, int]:
    result = dict(d1)
    for key, value in d2.items():
        result[key] = result.get(key, 0) + value
    return result

print(merge_dicts({"a": 1, "b": 2}, {"b": 3, "c": 4}))

class UpperCaseMeta(type):
    def __new__(mcs, name, bases, namespace):
        upper_namespace = {}
        for key, value in namespace.items():
            if key.startswith("__"):
                upper_namespace[key] = value
            else:
                upper_namespace[key.upper()] = value
        return super().__new__(mcs, name, bases, upper_namespace)

class Config(metaclass=UpperCaseMeta):
    debug = True
    version = "1.0"

print(Config.DEBUG)
print(Config.VERSION)

