answer:
def retry(times):
    def decorator(func):
        def wrapper(*args, **kwargs):
            for attempt in range(times):
                try:
                    return func(*args, **kwargs)
                except Exception:
                    if attempt == times - 1:
                        raise
        return wrapper
    return decorator

attempts = []

@retry(3)
def flaky():
    attempts.append(1)
    if len(attempts) < 2:
        raise ValueError("fail")
    return "ok"

print(flaky())

question:
Fill in the blank to recursively flatten a nested list, then print the flattened result:

def flatten(nested):
    for item in nested:
        if isinstance(item, list):
            ______ flatten(item)
        else:
            yield item

print(list(flatten([1, [2, [3, 4]], 5])))

answer:
def flatten(nested):
    for item in nested:
        if isinstance(item, list):
            yield from flatten(item)
        else:
            yield item

print(list(flatten([1, [2, [3, 4]], 5])))

